+    /// All extension IDs and their MAP estimates.
+    pub fn summary(&self) -> BTreeMap<String, RiskState> {
+        self.updaters
+            .iter()
+            .map(|u| (u.extension_id.clone(), u.posterior.map_estimate()))
+            .collect()
+    }
